MOD = 10**9 + 7

def get_prime_factors(x):
    """Get prime factors of x."""
    factors = set()
    d = 2
    while d * d <= x:
        while x % d == 0:
            factors.add(d)
            x //= d
        d += 1
    if x > 1:
        factors.add(x)
    return factors

def inv(x, mod=MOD):
    """Compute modular inverse using Fermat's little theorem."""
    return pow(x, mod - 2, mod)

def count_coprime(a, m):
    """Count numbers in [1, m] coprime to a using inclusion-exclusion."""
    primes = list(get_prime_factors(a))
    n = len(primes)
    result = 0
    for mask in range(1 << n):
        prod = 1
        cnt = 0
        for i in range(n):
            if mask & (1 << i):
                prod *= primes[i]
                cnt += 1
        if cnt % 2 == 0:
            result += m // prod
        else:
            result -= m // prod
    return result
